111→fn hypot(z: vec2f) -> f32 {
112→    var t: f32 = 0;
113→    var x: f32 = abs(z.x);
114→    let y: f32 = abs(z.y);
115→    t = min(x, y);
116→    x = max(x, y);
117→    t = t / x;
