141→fn geometrySchlickGGX(nDotV: f32, roughness: f32) -> f32 {
142→    let r: f32 = roughness + 1.;
143→    let k: f32 = r * r / 8.;
144→    // float k = roughness * roughness / 2.;
145→
146→    let num: f32 = nDotV;
